import{_ as l,u as c,o as d,c as p,a as t,b as a,d as i,w as s,r as m,S as o,e as r}from"./index-C_lTwF0q.js";const v="/assets/mani_pianoforte_3_bn-Bbr8VdHy.JPG",b={class:"musica"},u={class:"section section--alt influences"},f={class:"container"},_={class:"influences__list"},g={class:"influence"},h={class:"influence__icon"},z={class:"influence"},B={class:"influence__icon"},y={class:"influence"},C={class:"influence__icon"},M={class:"influence"},L={class:"influence__icon"},S={class:"influence"},I={class:"influence__icon"},x={class:"section section--dark cta-section"},P={class:"container",style:{"text-align":"center"}},R={style:{display:"flex",gap:"1rem","justify-content":"center","flex-wrap":"wrap","margin-top":"1.5rem"}},N={__name:"MusicaPage",setup(w){return c({title:"Musica e Repertorio | Chiara Dalla Torre",meta:[{name:"description",content:"Scopri il repertorio di Chiara Dalla Torre: dalle compositrici dimenticate come Clara Schumann e Fanny Mendelssohn, ai maestri che hanno ispirato il suo percorso pianistico."},{name:"keywords",content:"repertorio pianoforte, compositrici donne, Clara Schumann, Fanny Mendelssohn, Amy Beach, Nadia Boulanger, pianoforte repertorio femminile, Bach Busoni"}]}),(D,e)=>{const n=m("router-link");return d(),p("div",b,[e[13]||(e[13]=t('<section class="page-hero" data-v-f2ab9eab><div class="container" data-v-f2ab9eab><h1 data-v-f2ab9eab>La Musica</h1><div class="section__divider" style="margin-top:1rem;" data-v-f2ab9eab></div><p class="page-hero__sub" data-v-f2ab9eab> Repertorio, compositrici dimenticate e musicisti che hanno segnato il mio percorso </p></div></section><section class="section women" data-v-f2ab9eab><div class="container" data-v-f2ab9eab><h2 class="section__title" data-v-f2ab9eab>Voci dal Silenzio: Le Compositrici Dimenticate</h2><div class="section__divider" data-v-f2ab9eab></div><p class="section__subtitle" data-v-f2ab9eab> Per secoli, donne straordinarie hanno composto musica di altissimo valore, spesso ai margini della storia. Riscoprirle è un atto di giustizia e di arricchimento musicale. </p><div class="women__intro" data-v-f2ab9eab><p data-v-f2ab9eab> Durante il mio percorso di formazione, ho avuto l&#39;opportunità di approfondire il tema della <strong data-v-f2ab9eab>donna-musicista</strong> attraverso un corso dedicato, dove sono state prese in esame le vite e le opere di compositrici che hanno vissuto ai margini in un periodo storico di enorme produzione musicale. </p><p data-v-f2ab9eab> Questa esperienza ha trasformato profondamente la mia visione del repertorio: non si tratta solo di riscoprire brani dimenticati, ma di restituire una voce a personalità artistiche che meritano il loro posto nella storia della musica. Oggi integro attivamente questo repertorio nelle mie lezioni e nei miei programmi. </p></div><div class="grid grid--3 composers-grid" data-v-f2ab9eab><div class="card composer" data-v-f2ab9eab><div class="composer__portrait" data-v-f2ab9eab>CS</div><h3 data-v-f2ab9eab>Clara Schumann</h3><p class="composer__years" data-v-f2ab9eab>1819 – 1896</p><p data-v-f2ab9eab> Pianista virtuosa e compositrice tedesca, moglie di Robert Schumann. Una delle più grandi interpreti del suo tempo, le sue composizioni rivelano un&#39;intensità espressiva straordinaria. Il suo <em data-v-f2ab9eab>Concerto per pianoforte in La minore</em>, scritto a soli 14 anni, testimonia un talento precoce ed eccezionale. </p></div><div class="card composer" data-v-f2ab9eab><div class="composer__portrait" data-v-f2ab9eab>FM</div><h3 data-v-f2ab9eab>Fanny Mendelssohn</h3><p class="composer__years" data-v-f2ab9eab>1805 – 1847</p><p data-v-f2ab9eab> Sorella di Felix Mendelssohn, fu una compositrice prolifica la cui produzione fu a lungo oscurata dal fratello. Le sue <em data-v-f2ab9eab>Lieder</em> e i lavori per pianoforte solo mostrano una sensibilità melodica e un&#39;originalità armonica che rivaleggia con i grandi del suo tempo. </p></div><div class="card composer" data-v-f2ab9eab><div class="composer__portrait" data-v-f2ab9eab>AB</div><h3 data-v-f2ab9eab>Amy Beach</h3><p class="composer__years" data-v-f2ab9eab>1867 – 1944</p><p data-v-f2ab9eab> Prima compositrice americana a scrivere una sinfonia di successo. Il suo stile unisce il tardo Romanticismo europeo con una sensibilità tipicamente americana. La sua <em data-v-f2ab9eab>Gaelic Symphony</em> e il <em data-v-f2ab9eab>Concerto per pianoforte</em> sono capolavori ancora oggi sottovalutati. </p></div><div class="card composer" data-v-f2ab9eab><div class="composer__portrait" data-v-f2ab9eab>CC</div><h3 data-v-f2ab9eab>Cécile Chaminade</h3><p class="composer__years" data-v-f2ab9eab>1857 – 1944</p><p data-v-f2ab9eab> Compositrice e pianista francese che godette di grande fama in vita. Le sue opere per pianoforte, tra cui i celebri <em data-v-f2ab9eab>Études de concert</em>, uniscono eleganza parigina e virtuosismo, rendendole perfette per lo studio del repertorio romantico francese. </p></div><div class="card composer" data-v-f2ab9eab><div class="composer__portrait" data-v-f2ab9eab>MB</div><h3 data-v-f2ab9eab>Mel Bonis</h3><p class="composer__years" data-v-f2ab9eab>1858 – 1937</p><p data-v-f2ab9eab> Pseudonimo di Mélanie Bonis, compositrice francese allieva di César Franck al Conservatorio di Parigi. La sua vasta produzione include pezzi per pianoforte di rara bellezza, con un linguaggio armonico raffinato che anticipa l&#39;impressionismo. </p></div><div class="card composer" data-v-f2ab9eab><div class="composer__portrait" data-v-f2ab9eab>NB</div><h3 data-v-f2ab9eab>Nadia Boulanger</h3><p class="composer__years" data-v-f2ab9eab>1887 – 1979</p><p data-v-f2ab9eab> Forse la più grande pedagoga musicale del XX secolo. Il suo metodo di insegnamento ha formato generazioni di compositori — da Copland a Piazzolla. Le sue opere didattiche e il suo pensiero sulla musica sono una fonte d&#39;ispirazione costante per il mio insegnamento. </p></div></div><div class="women__more" data-v-f2ab9eab><p data-v-f2ab9eab> Tra le altre compositrici che studio e propongo ai miei allievi: <strong data-v-f2ab9eab>Lili Boulanger</strong>, sorella minore di Nadia e prima donna a vincere il Prix de Rome per la composizione, e <strong data-v-f2ab9eab>Sadie Harrison</strong>, compositrice contemporanea che continua a portare avanti la tradizione della musica scritta da donne. </p><p data-v-f2ab9eab> Integrare questo repertorio nello studio del pianoforte non è solo un atto di riscoperta: è un modo per offrire agli allievi una visione più completa e onesta della storia della musica. </p></div></div></section>',2)),a("section",u,[a("div",f,[e[5]||(e[5]=a("h2",{class:"section__title"},"Musicisti che Mi Hanno Ispirata",-1)),e[6]||(e[6]=a("div",{class:"section__divider"},null,-1)),e[7]||(e[7]=a("p",{class:"section__subtitle"}," Maestri il cui insegnamento e la cui arte hanno plasmato il mio modo di suonare e insegnare ",-1)),a("div",_,[a("div",g,[a("div",h,[i(o,{name:"piano",size:28,color:"var(--color-accent)"})]),e[0]||(e[0]=a("div",{class:"influence__content"},[a("h3",null,"Pietro De Maria"),a("p",null," Pianista italiano tra i più raffinati della sua generazione. La sua integrale delle Sonate di Beethoven e l'approccio rigoroso ma poetico all'interpretazione sono un riferimento costante nel mio lavoro. La sua capacità di rendere ogni nota necessaria è un insegnamento che porto con me. ")],-1))]),a("div",z,[a("div",B,[i(o,{name:"piano",size:28,color:"var(--color-accent)"})]),e[1]||(e[1]=a("div",{class:"influence__content"},[a("h3",null,"Andrea Lucchesini"),a("p",null," Allievo di Maria Tipo, è un interprete di riferimento nel panorama italiano. La sua attenzione maniacale per il dettaglio sonoro e la chiarezza strutturale delle sue interpretazioni mi hanno insegnato che la bellezza nasce dalla precisione. ")],-1))]),a("div",y,[a("div",C,[i(o,{name:"piano",size:28,color:"var(--color-accent)"})]),e[2]||(e[2]=a("div",{class:"influence__content"},[a("h3",null,"Filippo Gamba"),a("p",null," Vincitore del Concorso Internazionale di Ginevra, Filippo Gamba combina un'intensità emotiva rara con una solidità tecnica impeccabile. Le sue Masterclass sono state fondamentali per il mio approccio all'interpretazione del repertorio romantico. ")],-1))]),a("div",M,[a("div",L,[i(o,{name:"piano",size:28,color:"var(--color-accent)"})]),e[3]||(e[3]=a("div",{class:"influence__content"},[a("h3",null,"Annibale Rebaudengo"),a("p",null," Didatta di riferimento nel panorama italiano, il suo lavoro sulla metodologia dell'insegnamento pianistico ha influenzato profondamente il mio approccio pedagogico. La sua visione dell'insegnamento come atto creativo risuona nel mio modo di condurre le lezioni. ")],-1))]),a("div",S,[a("div",I,[i(o,{name:"piano",size:28,color:"var(--color-accent)"})]),e[4]||(e[4]=a("div",{class:"influence__content"},[a("h3",null,"Il M° Irene Russo"),a("p",null," La mia insegnante al Conservatorio, che mi ha guidata negli anni decisivi della mia formazione. Il suo approccio paziente e attento alle esigenze dell'allievo è il modello a cui mi ispiro quotidianamente nel mio insegnamento. ")],-1))])])])]),e[14]||(e[14]=t('<section class="section discography" data-v-f2ab9eab><div class="container" data-v-f2ab9eab><div class="disco__grid" data-v-f2ab9eab><div class="disco__content" data-v-f2ab9eab><h2 data-v-f2ab9eab>Discografia e Repertorio</h2><div class="section__divider" style="margin-left:0;" data-v-f2ab9eab></div><p data-v-f2ab9eab> Nel 2016 ho realizzato la mia <strong data-v-f2ab9eab>prima produzione discografica</strong> con musiche di <em data-v-f2ab9eab>Bach/Busoni</em>, pubblicata dal Conservatorio di Castelfranco Veneto. Un progetto che raccoglie il culmine del mio percorso di studi e la mia passione per la trascrizione pianistica. </p><p data-v-f2ab9eab> Il mio repertorio spazia dal <strong data-v-f2ab9eab>Barocco</strong> al <strong data-v-f2ab9eab>Novecento</strong>, con particolare attenzione a: </p><ul class="disco__list" data-v-f2ab9eab><li data-v-f2ab9eab>J.S. Bach e le trascrizioni di Busoni</li><li data-v-f2ab9eab>Il repertorio classico: Mozart, Beethoven</li><li data-v-f2ab9eab>Il grande Romanticismo: Chopin, Schumann, Liszt</li><li data-v-f2ab9eab>La scuola francese: Debussy, Ravel</li><li data-v-f2ab9eab>Il repertorio delle compositrici dimenticate</li><li data-v-f2ab9eab>La musica da camera con flauto traverso</li></ul></div><div class="disco__visual" data-v-f2ab9eab><div class="disco__album" data-v-f2ab9eab><img src="'+v+'" alt="Mani al pianoforte - Bach Busoni" class="disco__album-photo" loading="lazy" data-v-f2ab9eab><div class="disco__album-label" data-v-f2ab9eab><strong data-v-f2ab9eab>Bach / Busoni</strong><small data-v-f2ab9eab>2016</small></div></div></div></div></div></section>',1)),a("section",x,[a("div",P,[e[10]||(e[10]=a("h2",null,"Esplora la Musica con Me",-1)),e[11]||(e[11]=a("div",{class:"section__divider",style:{background:"var(--color-accent)"}},null,-1)),e[12]||(e[12]=a("p",{style:{"max-width":"520px",margin:"0 auto",color:"rgba(240,236,228,0.85)","font-size":"1.05rem"}}," Dalla musica classica al repertorio femminile dimenticato, ogni lezione è un viaggio nella bellezza del pianoforte. ",-1)),a("div",R,[i(n,{to:"/lezioni",class:"btn btn--light"},{default:s(()=>[...e[8]||(e[8]=[r("Scopri le Lezioni",-1)])]),_:1}),i(n,{to:"/contatti",class:"btn btn--light"},{default:s(()=>[...e[9]||(e[9]=[r("Contattami",-1)])]),_:1})])])])])}}},k=l(N,[["__scopeId","data-v-f2ab9eab"]]);export{k as default};
